    @Test
    fun `getClubId returns empty string when not configured`() {
        assertThat(settingsService.getClubId()).isEmpty()
    }

    @Test
    fun `setClubId persists the value`() {
        settingsService.setClubId("12345")

        assertThat(settingsService.getClubId()).isEqualTo("12345")
    }

    @Test
    fun `setClubId with blank clears the value`() {
        settingsService.setClubId("12345")
        settingsService.setClubId("")

        assertThat(settingsService.getClubId()).isEmpty()
    }

    // -- Platform -------------------------------------------------------------

    @Test
    fun `getPlatform returns empty string when not configured`() {
        assertThat(settingsService.getPlatform()).isEmpty()
    }

    @Test
    fun `setPlatform persists the value`() {
        settingsService.setPlatform("common-gen5")

        assertThat(settingsService.getPlatform()).isEqualTo("common-gen5")
    }

    @Test
    fun `setPlatform with blank clears the value`() {
        settingsService.setPlatform("common-gen5")
        settingsService.setPlatform("")

        assertThat(settingsService.getPlatform()).isEmpty()
    }

    // -- Polling Interval -----------------------------------------------------

    @Test
    fun `getPollingIntervalMs returns default when not configured`() {
        assertThat(settingsService.getPollingIntervalMs()).isEqualTo(60_000L)
    }

    @Test
    fun `getPollingIntervalMs returns custom default when specified`() {
        assertThat(settingsService.getPollingIntervalMs(120_000L)).isEqualTo(120_000L)
    }

    @Test
    fun `setPollingIntervalMs persists the value`() {
        settingsService.setPollingIntervalMs(120_000L)

        assertThat(settingsService.getPollingIntervalMs()).isEqualTo(120_000L)
    }

    // -- Clear All ------------------------------------------------------------

    @Test
    fun `clearAll removes all saved settings`() {
        settingsService.setWebhookUrl("https://discord.com/api/webhooks/123/abc")
        settingsService.setHistoryWebhookUrl("https://discord.com/api/webhooks/456/def")
        settingsService.setNetworkEnabled(true)
        settingsService.setClubId("12345")
        settingsService.setPlatform("common-gen5")
        settingsService.setPollingIntervalMs(120_000L)

        settingsService.clearAll()

        assertThat(settingsService.getWebhookUrl()).isEmpty()
        assertThat(settingsService.getHistoryWebhookUrl()).isEmpty()
        assertThat(settingsService.isNetworkEnabled()).isFalse()
        assertThat(settingsService.getClubId()).isEmpty()
        assertThat(settingsService.getPlatform()).isEmpty()
        assertThat(settingsService.getPollingIntervalMs()).isEqualTo(60_000L)
    }

    // -- Persistence across instances -----------------------------------------

    @Test
    fun `settings persist across service instances`() {
        settingsService.setWebhookUrl("https://discord.com/api/webhooks/999/xyz")

        // Create a new instance to verify persistence
        val newInstance = SettingsService()

        assertThat(newInstance.getWebhookUrl()).isEqualTo("https://discord.com/api/webhooks/999/xyz")
    }
}

package com.eafc26.discordstats.scheduler

import com.eafc26.discordstats.service.MatchNotifierService
import com.eafc26.discordstats.service.NotifyLatestService
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test
import org.mockito.kotlin.any
import org.mockito.kotlin.doAnswer
import org.mockito.kotlin.mock
import org.mockito.kotlin.times
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import java.util.concurrent.CountDownLatch
import java.util.concurrent.Executors
import java.util.concurrent.TimeUnit

class MatchPollingSchedulerTest {

    private val service: MatchNotifierService = mock()
    private val notifyLatestService: NotifyLatestService = mock()
    private val statusHolder: PollingStatusHolder = PollingStatusHolder()

    @BeforeEach
    fun setUp() {
        // Default: runIfIdle always runs the action
        whenever(notifyLatestService.runIfIdle(any())).doAnswer { invocation ->
            val action = invocation.getArgument<() -> Unit>(0)
            action()
            true
        }
    }

    @Test
    fun `poll invokes service process`() {
        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        scheduler.poll()
        verify(service).process(any())
    }

    @Test
    fun `exception from service does not propagate out of poll`() {
        whenever(service.process(any())).thenThrow(RuntimeException("boom"))
        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        scheduler.poll() // must not throw
    }

    @Test
    fun `concurrent firing is skipped - service called only once`() {
        val started = CountDownLatch(1)
        val release = CountDownLatch(1)

        // The first call runs the action after signaling start
        var firstCall = true
        whenever(notifyLatestService.runIfIdle(any())).doAnswer { invocation ->
            if (firstCall) {
                firstCall = false
                val action = invocation.getArgument<() -> Unit>(0)
                started.countDown()
                release.await(5, TimeUnit.SECONDS)
                action()
                true
            } else {
                // Second call while first is running — return false (busy)
                false
            }
        }

        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        val executor = Executors.newFixedThreadPool(2)

        try {
            executor.submit { scheduler.poll() }
            started.await(5, TimeUnit.SECONDS)
            // Second firing while first is still running — should be skipped
            executor.submit { scheduler.poll() }.get(5, TimeUnit.SECONDS)
            release.countDown()
            executor.shutdown()
            executor.awaitTermination(5, TimeUnit.SECONDS)
        } finally {
            executor.shutdownNow()
        }

        verify(service, times(1)).process(any())
    }
}

package com.eafc26.discordstats.scheduler

import com.eafc26.discordstats.service.MatchNotifierService
import com.eafc26.discordstats.service.NotifyLatestService
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test
import org.mockito.kotlin.any
import org.mockito.kotlin.doAnswer
import org.mockito.kotlin.mock
import org.mockito.kotlin.never
import org.mockito.kotlin.times
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import org.springframework.scheduling.annotation.Scheduled
import java.util.concurrent.CountDownLatch
import java.util.concurrent.Executors
import java.util.concurrent.TimeUnit
import java.util.concurrent.atomic.AtomicInteger

class MatchPollingSchedulerTest {

    private val service: MatchNotifierService = mock()
    private val notifyLatestService: NotifyLatestService = mock()
    private val statusHolder: PollingStatusHolder = PollingStatusHolder()

    @BeforeEach
    fun setUp() {
        // Default: runIfIdle always runs the action
        whenever(notifyLatestService.runIfIdle(any())).doAnswer { invocation ->
            val action = invocation.getArgument<() -> Unit>(0)
            action()
            true
        }
    }

    // -- Interval Configuration --

    @Test
    fun `INTERVAL_MS is 60 seconds`() {
        assertThat(MatchPollingScheduler.INTERVAL_MS).isEqualTo(60_000L)
    }

    @Test
    fun `statusHolder intervalSeconds is set to 60 on initialization`() {
        MatchPollingScheduler(service, notifyLatestService, statusHolder)
        assertThat(statusHolder.intervalSeconds).isEqualTo(60)
    }

    @Test
    fun `poll method uses fixedRate annotation with 60000ms and initialDelay 0`() {
        val pollMethod = MatchPollingScheduler::class.java.getMethod("poll")
        val scheduled = pollMethod.getAnnotation(Scheduled::class.java)

        assertThat(scheduled).isNotNull
        assertThat(scheduled.fixedRate).isEqualTo(60_000L)
        assertThat(scheduled.initialDelay).isEqualTo(0L)
        // Verify it's NOT using fixedDelay
        assertThat(scheduled.fixedDelay).isEqualTo(-1L)
        assertThat(scheduled.fixedDelayString).isEmpty()
    }

    // -- Immediate First Execution --

    @Test
    fun `poll invokes service process immediately`() {
        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        scheduler.poll()
        verify(service).process(any())
    }

    @Test
    fun `initialDelay is 0 so first execution runs immediately`() {
        val pollMethod = MatchPollingScheduler::class.java.getMethod("poll")
        val scheduled = pollMethod.getAnnotation(Scheduled::class.java)
        assertThat(scheduled.initialDelay).isEqualTo(0L)
    }

    // -- Fresh HTTP Request Every Cycle --

    @Test
    fun `each poll cycle invokes service process for fresh HTTP request`() {
        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)

        scheduler.poll()
        scheduler.poll()
        scheduler.poll()

        verify(service, times(3)).process(any())
    }

    // -- Exception Handling --

    @Test
    fun `exception from service does not propagate out of poll`() {
        whenever(service.process(any())).thenThrow(RuntimeException("boom"))
        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        scheduler.poll() // must not throw
    }

    @Test
    fun `exception sets lastResult to error message`() {
        whenever(service.process(any())).thenThrow(RuntimeException("boom"))
        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        scheduler.poll()
        assertThat(statusHolder.lastResult).isEqualTo("EA indisponível. Nova tentativa em 1 minuto.")
    }

    // -- Concurrency / Overlapping Executions --

    @Test
    fun `overlapping execution is skipped - service called only once`() {
        val started = CountDownLatch(1)
        val release = CountDownLatch(1)
        val callCount = AtomicInteger(0)

        whenever(notifyLatestService.runIfIdle(any())).doAnswer { invocation ->
            val attempt = callCount.incrementAndGet()
            if (attempt == 1) {
                // First call: signal start, wait for release, then run action
                val action = invocation.getArgument<() -> Unit>(0)
                started.countDown()
                release.await(5, TimeUnit.SECONDS)
                action()
                true
            } else {
                // Subsequent calls while first is running — return false (busy)
                false
            }
        }

        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        val executor = Executors.newFixedThreadPool(2)

        try {
            executor.submit { scheduler.poll() }
            started.await(5, TimeUnit.SECONDS)
            // Second firing while first is still running — should be skipped
            executor.submit { scheduler.poll() }.get(5, TimeUnit.SECONDS)
            release.countDown()
            executor.shutdown()
            executor.awaitTermination(5, TimeUnit.SECONDS)
        } finally {
            executor.shutdownNow()
        }

        verify(service, times(1)).process(any())
    }

    @Test
    fun `skipped overlapping cycle does not stop later cycles`() {
        val callCount = AtomicInteger(0)
        val started = CountDownLatch(1)
        val release = CountDownLatch(1)

        whenever(notifyLatestService.runIfIdle(any())).doAnswer { invocation ->
            val attempt = callCount.incrementAndGet()
            when (attempt) {
                1 -> {
                    // First call: run slowly
                    val action = invocation.getArgument<() -> Unit>(0)
                    started.countDown()
                    release.await(5, TimeUnit.SECONDS)
                    action()
                    true
                }
                2 -> {
                    // Second call: busy (overlapping)
                    false
                }
                else -> {
                    // Third+ calls: run normally
                    val action = invocation.getArgument<() -> Unit>(0)
                    action()
                    true
                }
            }
        }

        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        val executor = Executors.newFixedThreadPool(3)

        try {
            // First poll (slow)
            executor.submit { scheduler.poll() }
            started.await(5, TimeUnit.SECONDS)

            // Second poll (should be skipped - busy)
            executor.submit { scheduler.poll() }.get(5, TimeUnit.SECONDS)

            // Release first poll
            release.countDown()
            Thread.sleep(100) // Let first poll complete

            // Third poll (should run normally)
            executor.submit { scheduler.poll() }.get(5, TimeUnit.SECONDS)

            executor.shutdown()
            executor.awaitTermination(5, TimeUnit.SECONDS)
        } finally {
            executor.shutdownNow()
        }

        // First and third polls should have called service
        verify(service, times(2)).process(any())
    }

    @Test
    fun `when busy lastResult shows verification in progress`() {
        whenever(notifyLatestService.runIfIdle(any())).thenReturn(false)

        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        scheduler.poll()

        assertThat(statusHolder.lastResult).isEqualTo("Uma verificação já está em andamento.")
        verify(service, never()).process(any())
    }

    // -- Status Updates --

    @Test
    fun `poll updates lastCheck timestamp`() {
        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        val before = java.time.Instant.now()
        scheduler.poll()
        val after = java.time.Instant.now()

        assertThat(statusHolder.lastCheck).isNotNull
        assertThat(statusHolder.lastCheck).isBetween(before, after)
    }

    @Test
    fun `poll updates nextCheck to 60 seconds from lastCheck`() {
        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        scheduler.poll()

        assertThat(statusHolder.nextCheck).isNotNull
        assertThat(statusHolder.lastCheck).isNotNull
        val diff = java.time.Duration.between(statusHolder.lastCheck, statusHolder.nextCheck)
        assertThat(diff.toMillis()).isEqualTo(60_000L)
    }

    @Test
    fun `running is true during execution and false after`() {
        val started = CountDownLatch(1)
        val release = CountDownLatch(1)
        var runningDuringExecution = false

        whenever(notifyLatestService.runIfIdle(any())).doAnswer { invocation ->
            val action = invocation.getArgument<() -> Unit>(0)
            started.countDown()
            release.await(5, TimeUnit.SECONDS)
            action()
            true
        }

        whenever(service.process(any())).doAnswer {
            runningDuringExecution = statusHolder.running
        }

        val scheduler = MatchPollingScheduler(service, notifyLatestService, statusHolder)
        val executor = Executors.newSingleThreadExecutor()

        try {
            executor.submit { scheduler.poll() }
            started.await(5, TimeUnit.SECONDS)
            release.countDown()
            executor.shutdown()
            executor.awaitTermination(5, TimeUnit.SECONDS)
        } finally {
            executor.shutdownNow()
        }

        assertThat(runningDuringExecution).isTrue()
        assertThat(statusHolder.running).isFalse()
    }

    // -- Fixed Rate Verification --

    @Test
    fun `fixed rate ensures schedule is not shifted by request duration`() {
        // This test verifies the annotation configuration
        // The actual fixed-rate behavior is handled by Spring's TaskScheduler
        val pollMethod = MatchPollingScheduler::class.java.getMethod("poll")
        val scheduled = pollMethod.getAnnotation(Scheduled::class.java)

        // fixedRate means: schedule at fixed intervals from start, not after completion
        assertThat(scheduled.fixedRate).isEqualTo(60_000L)
        // fixedDelay would mean: wait N ms after completion before next start
        assertThat(scheduled.fixedDelay).isEqualTo(-1L) // -1 means not set
    }

    // -- Initialization --

    @Test
    fun `scheduler sets enabled to true on initialization`() {
        val holder = PollingStatusHolder()
        assertThat(holder.enabled).isFalse() // default

        MatchPollingScheduler(service, notifyLatestService, holder)

        assertThat(holder.enabled).isTrue()
    }
}

package com.eafc26.discordstats.service

import com.eafc26.discordstats.config.AppProperties
import com.eafc26.discordstats.config.EaProperties
import com.eafc26.discordstats.config.PollingProperties
import com.eafc26.discordstats.discord.DiscordDeliveryException
import com.eafc26.discordstats.discord.DiscordWebhookClient
import com.eafc26.discordstats.ea.EaApiResult
import com.eafc26.discordstats.ea.EaClubsGateway
import com.eafc26.discordstats.ea.model.ClubDetails
import com.eafc26.discordstats.ea.model.ClubMatchEntry
import com.eafc26.discordstats.ea.model.MatchResponse
import com.eafc26.discordstats.store.PublishedMatchStore
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test
import org.mockito.kotlin.any
import org.mockito.kotlin.mock
import org.mockito.kotlin.never
import org.mockito.kotlin.times
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever

class MatchNotifierServiceTest {

    private val gateway: EaClubsGateway = mock()
    private val store: PublishedMatchStore = mock()
    private val discord: DiscordWebhookClient = mock()

    private val clubId = "12345"

    private fun makeService(publishExistingOnFirstRun: Boolean = false): MatchNotifierService {
        val props = AppProperties(
            ea = EaProperties(clubId = clubId),
            polling = PollingProperties(publishExistingOnFirstRun = publishExistingOnFirstRun),
        )
        return MatchNotifierService(gateway, store, discord, props)
    }

    @BeforeEach
    fun setUp() {
        whenever(store.loadIds()).thenReturn(emptySet())
    }

    // -- EA unavailable --

    @Test
    fun `EA unavailable does not crash — nothing is sent`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Unavailable(503, "down"))
        makeService().process()
        verify(discord, never()).send(any())
    }

    @Test
    fun `EA no matches does not crash — nothing is sent`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.NoMatches)
        makeService().process()
        verify(discord, never()).send(any())
    }

    // -- First run --

    @Test
    fun `first run establishes baseline without publishing any matches`() {
        val matches = listOf(match("m1", ts = 1000), match("m2", ts = 2000))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(emptySet())

        makeService(publishExistingOnFirstRun = false).process()

        verify(discord, never()).send(any())
        verify(store).saveIds(setOf("m1", "m2"))
    }

    @Test
    fun `first run with publishExistingOnFirstRun=true publishes all matches`() {
        val matches = listOf(match("m1", ts = 1000), match("m2", ts = 2000))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        // store.loadIds() returns empty -> first-run path taken; no recursive process() call

        makeService(publishExistingOnFirstRun = true).process()

        verify(discord, times(2)).send(any())
    }

    // -- Normal processing --

    @Test
    fun `already published match is not sent again`() {
        val matches = listOf(match("m1"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        makeService().process()

        verify(discord, never()).send(any())
    }

    @Test
    fun `new match is published and saved`() {
        val matches = listOf(match("m2"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        makeService().process()

        verify(discord).send(any())
        verify(store).saveIds(setOf("m1", "m2"))
    }

    @Test
    fun `multiple new matches are processed oldest-first`() {
        val matches = listOf(match("newer", ts = 2000), match("older", ts = 1000))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("published"))

        val savedOrder = mutableListOf<Set<String>>()
        whenever(store.saveIds(any())).thenAnswer { inv ->
            savedOrder += inv.getArgument<Set<String>>(0).toSet()
            Unit
        }

        makeService().process()

        // service processes oldest-first and persists after each send
        assertThat(savedOrder).hasSize(2)
        assertThat(savedOrder[0]).contains("older")
        assertThat(savedOrder[0]).doesNotContain("newer")
        assertThat(savedOrder[1]).contains("older", "newer")
    }

    @Test
    fun `Discord delivery failure does not mark match as published`() {
        val matches = listOf(match("m1"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(emptySet<String>(), emptySet())
        whenever(store.loadIds()).thenReturn(setOf("baseline"))
        whenever(discord.send(any())).thenThrow(DiscordDeliveryException("503 error"))

        makeService().process()

        // Should NOT save m1 as published
        verify(store, never()).saveIds(org.mockito.kotlin.check { ids -> assertThat(ids).contains("m1") })
    }

    @Test
    fun `missing webhook URL aborts cycle — no further matches are processed`() {
        val matches = listOf(match("m1"), match("m2"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("baseline"))
        whenever(discord.send(any())).thenThrow(IllegalStateException("webhook not configured"))

        makeService().process()

        // IllegalStateException should abort — only the first send attempt happens
        verify(discord, times(1)).send(any())
    }

    // -- History webhook --

    @Test
    fun `history webhook is called for each newly published match`() {
        val matches = listOf(match("m2"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        makeService().process()

        verify(discord).send(any())
        verify(discord).sendHistory(any())
    }

    @Test
    fun `history webhook is not called for already published match`() {
        val matches = listOf(match("m1"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        makeService().process()

        verify(discord, never()).send(any())
        verify(discord, never()).sendHistory(any())
    }

    @Test
    fun `history webhook failure does not prevent persistence of successful send`() {
        val matches = listOf(match("m2"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))
        // sendHistory never throws (it's fire-and-forget), but simulate a no-op to be explicit
        org.mockito.kotlin.doNothing().whenever(discord).sendHistory(any())

        makeService().process()

        // Main send and persistence must still complete
        verify(discord).send(any())
        verify(store).saveIds(setOf("m1", "m2"))
    }

    @Test
    fun `history is called once per match — not again when already published on next cycle`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("baseline"))

        val service = makeService()

        // First cycle: m1 is new, should publish and send history
        service.process()
        verify(discord, times(1)).sendHistory(any())

        // Second cycle: m1 now in store, should be skipped entirely
        whenever(store.loadIds()).thenReturn(setOf("baseline", "m1"))
        service.process()
        verify(discord, times(1)).sendHistory(any()) // still only 1 total
    }

    @Test
    fun `history is sent for each match when multiple new matches are published`() {
        val matches = listOf(match("m2", ts = 2000), match("m3", ts = 3000))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))
        whenever(store.saveIds(any())).thenAnswer { Unit }

        makeService().process()

        verify(discord, times(2)).sendHistory(any())
    }

    // -- Helpers --

    private fun match(id: String, ts: Long = 1000L) = MatchResponse(
        matchId = id,
        timestamp = ts,
        clubs = mapOf(
            clubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
            "99999" to ClubMatchEntry(details = ClubDetails(name = "Opp"), score = "0", result = "0"),
        ),
        players = emptyMap(),
    )
}

package com.eafc26.discordstats.service

import com.eafc26.discordstats.config.AppProperties
import com.eafc26.discordstats.config.EaProperties
import com.eafc26.discordstats.config.PollingProperties
import com.eafc26.discordstats.discord.DiscordDeliveryException
import com.eafc26.discordstats.discord.DiscordWebhookClient
import com.eafc26.discordstats.ea.EaApiResult
import com.eafc26.discordstats.ea.EaClubsGateway
import com.eafc26.discordstats.ea.model.ClubDetails
import com.eafc26.discordstats.ea.model.ClubMatchEntry
import com.eafc26.discordstats.ea.model.MatchResponse
import com.eafc26.discordstats.store.PublishedMatchStore
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test
import org.mockito.kotlin.any
import org.mockito.kotlin.mock
import org.mockito.kotlin.never
import org.mockito.kotlin.times
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever

class MatchNotifierServiceTest {

    private val gateway: EaClubsGateway = mock()
    private val store: PublishedMatchStore = mock()
    private val discord: DiscordWebhookClient = mock()

    private val clubId = "12345"

    private fun makeService(publishExistingOnFirstRun: Boolean = false): MatchNotifierService {
        val props = AppProperties(
            ea = EaProperties(clubId = clubId),
            polling = PollingProperties(publishExistingOnFirstRun = publishExistingOnFirstRun),
        )
        return MatchNotifierService(gateway, store, discord, props)
    }

    @BeforeEach
    fun setUp() {
        whenever(store.loadIds()).thenReturn(emptySet())
    }

    // -- EA unavailable --

    @Test
    fun `EA unavailable does not crash — nothing is sent`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Unavailable(503, "down"))
        makeService().process()
        verify(discord, never()).send(any())
    }

    @Test
    fun `EA no matches does not crash — nothing is sent`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.NoMatches)
        makeService().process()
        verify(discord, never()).send(any())
    }

    // -- First run --

    @Test
    fun `first run establishes baseline without publishing any matches`() {
        val matches = listOf(match("m1", ts = 1000), match("m2", ts = 2000))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(emptySet())

        makeService(publishExistingOnFirstRun = false).process()

        verify(discord, never()).send(any())
        verify(store).saveIds(setOf("m1", "m2"))
    }

    @Test
    fun `first run with publishExistingOnFirstRun=true publishes all matches`() {
        val matches = listOf(match("m1", ts = 1000), match("m2", ts = 2000))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        // store.loadIds() returns empty -> first-run path taken; no recursive process() call

        makeService(publishExistingOnFirstRun = true).process()

        verify(discord, times(2)).send(any())
    }

    // -- Normal processing --

    @Test
    fun `already published match is not sent again`() {
        val matches = listOf(match("m1"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        makeService().process()

        verify(discord, never()).send(any())
    }

    @Test
    fun `new match is published and saved`() {
        val matches = listOf(match("m2"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        makeService().process()

        verify(discord).send(any())
        verify(store).saveIds(setOf("m1", "m2"))
    }

    @Test
    fun `multiple new matches are processed oldest-first`() {
        val matches = listOf(match("newer", ts = 2000), match("older", ts = 1000))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("published"))

        val savedOrder = mutableListOf<Set<String>>()
        whenever(store.saveIds(any())).thenAnswer { inv ->
            savedOrder += inv.getArgument<Set<String>>(0).toSet()
            Unit
        }

        makeService().process()

        // service processes oldest-first and persists after each send
        assertThat(savedOrder).hasSize(2)
        assertThat(savedOrder[0]).contains("older")
        assertThat(savedOrder[0]).doesNotContain("newer")
        assertThat(savedOrder[1]).contains("older", "newer")
    }

    @Test
    fun `Discord delivery failure does not mark match as published`() {
        val matches = listOf(match("m1"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(emptySet<String>(), emptySet())
        whenever(store.loadIds()).thenReturn(setOf("baseline"))
        whenever(discord.send(any())).thenThrow(DiscordDeliveryException("503 error"))

        makeService().process()

        // Should NOT save m1 as published
        verify(store, never()).saveIds(org.mockito.kotlin.check { ids -> assertThat(ids).contains("m1") })
    }

    @Test
    fun `missing webhook URL aborts cycle — no further matches are processed`() {
        val matches = listOf(match("m1"), match("m2"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("baseline"))
        whenever(discord.send(any())).thenThrow(IllegalStateException("webhook not configured"))

        makeService().process()

        // IllegalStateException should abort — only the first send attempt happens
        verify(discord, times(1)).send(any())
    }

    // -- History webhook --

    @Test
    fun `history webhook is called for each newly published match`() {
        val matches = listOf(match("m2"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        makeService().process()

        verify(discord).send(any())
        verify(discord).sendHistory(any())
    }

    @Test
    fun `history webhook is not called for already published match`() {
        val matches = listOf(match("m1"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        makeService().process()

        verify(discord, never()).send(any())
        verify(discord, never()).sendHistory(any())
    }

    @Test
    fun `history webhook failure does not prevent persistence of successful send`() {
        val matches = listOf(match("m2"))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))
        // sendHistory never throws (it's fire-and-forget), but simulate a no-op to be explicit
        org.mockito.kotlin.doNothing().whenever(discord).sendHistory(any())

        makeService().process()

        // Main send and persistence must still complete
        verify(discord).send(any())
        verify(store).saveIds(setOf("m1", "m2"))
    }

    @Test
    fun `history is called once per match — not again when already published on next cycle`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("baseline"))

        val service = makeService()

        // First cycle: m1 is new, should publish and send history
        service.process()
        verify(discord, times(1)).sendHistory(any())

        // Second cycle: m1 now in store, should be skipped entirely
        whenever(store.loadIds()).thenReturn(setOf("baseline", "m1"))
        service.process()
        verify(discord, times(1)).sendHistory(any()) // still only 1 total
    }

    @Test
    fun `history is sent for each match when multiple new matches are published`() {
        val matches = listOf(match("m2", ts = 2000), match("m3", ts = 3000))
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(matches))
        whenever(store.loadIds()).thenReturn(setOf("m1"))
        whenever(store.saveIds(any())).thenAnswer { Unit }

        makeService().process()

        verify(discord, times(2)).sendHistory(any())
    }

    // -- Fresh HTTP Request Every Cycle --

    @Test
    fun `each process cycle performs a fresh EA API request`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(emptyList()))
        whenever(store.loadIds()).thenReturn(setOf("baseline"))

        val service = makeService()

        service.process()
        service.process()
        service.process()

        verify(gateway, times(3)).getLatestMatches(clubId)
    }

    @Test
    fun `new match from EA API is published on first poll cycle that returns it`() {
        val match = match("new-match", ts = 9999)

        // Simulate: first poll returns no new matches, second poll returns the new match
        whenever(gateway.getLatestMatches(clubId))
            .thenReturn(EaApiResult.Success(emptyList()))
            .thenReturn(EaApiResult.Success(listOf(match)))

        whenever(store.loadIds()).thenReturn(setOf("baseline"))

        val service = makeService()

        // First poll: no new matches
        service.process()
        verify(discord, never()).send(any())

        // Second poll: new match appears in EA API response -> publish immediately
        service.process()
        verify(discord, times(1)).send(any())
        verify(store).saveIds(setOf("baseline", "new-match"))
    }

    // -- Helpers --

    private fun match(id: String, ts: Long = 1000L) = MatchResponse(
        matchId = id,
        timestamp = ts,
        clubs = mapOf(
            clubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
            "99999" to ClubMatchEntry(details = ClubDetails(name = "Opp"), score = "0", result = "0"),
        ),
        players = emptyMap(),
    )
}

package com.eafc26.discordstats.service

import com.eafc26.discordstats.config.AppProperties
import com.eafc26.discordstats.config.EaProperties
import com.eafc26.discordstats.discord.DiscordDeliveryException
import com.eafc26.discordstats.discord.DiscordWebhookClient
import com.eafc26.discordstats.ea.EaApiResult
import com.eafc26.discordstats.ea.EaClubsGateway
import com.eafc26.discordstats.ea.model.ClubDetails
import com.eafc26.discordstats.ea.model.ClubMatchEntry
import com.eafc26.discordstats.ea.model.MatchResponse
import com.eafc26.discordstats.store.PublishedMatchStore
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test
import org.mockito.kotlin.any
import org.mockito.kotlin.doThrow
import org.mockito.kotlin.mock
import org.mockito.kotlin.never
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import java.util.concurrent.CountDownLatch
import java.util.concurrent.Executors
import java.util.concurrent.TimeUnit

class NotifyLatestServiceTest {

    private lateinit var gateway: EaClubsGateway
    private lateinit var store: PublishedMatchStore
    private lateinit var webhookClient: DiscordWebhookClient
    private lateinit var service: NotifyLatestService

    private val clubId = "12345"
    private val props = AppProperties(ea = EaProperties(clubId = "12345", clubName = "Test FC"))

    @BeforeEach
    fun setUp() {
        gateway = mock()
        store = mock()
        webhookClient = mock()
        service = NotifyLatestService(gateway, store, webhookClient, props)
        whenever(store.loadIds()).thenReturn(emptySet())
    }

    @Test
    fun `sends notification for new match and persists match id`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))

        val result = service.notifyLatest()

        assertThat(result).isInstanceOf(NotifyResult.Sent::class.java)
        val sent = result as NotifyResult.Sent
        assertThat(sent.summary).contains("Test FC")
        verify(webhookClient).send(any())
        verify(store).saveIds(setOf("m1"))
    }

    @Test
    fun `skips already published match and does not call webhook`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        val result = service.notifyLatest()

        assertThat(result).isInstanceOf(NotifyResult.AlreadyPublished::class.java)
        verify(webhookClient, never()).send(any())
        verify(store, never()).saveIds(any())
    }

    @Test
    fun `does not persist match id when Discord delivery fails`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        doThrow(DiscordDeliveryException("HTTP 500")).whenever(webhookClient).send(any())

        val result = service.notifyLatest()

        assertThat(result).isEqualTo(NotifyResult.DiscordError)
        verify(store, never()).saveIds(any())
    }

    @Test
    fun `returns DiscordError when webhook is not configured`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        doThrow(IllegalStateException("Discord webhook URL is not configured")).whenever(webhookClient).send(any())

        val result = service.notifyLatest()

        assertThat(result).isEqualTo(NotifyResult.DiscordError)
        verify(store, never()).saveIds(any())
    }

    @Test
    fun `returns EaUnavailable when EA API is down`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Unavailable(503, "down"))

        val result = service.notifyLatest()

        assertThat(result).isEqualTo(NotifyResult.EaUnavailable)
        verify(webhookClient, never()).send(any())
    }

    @Test
    fun `returns EaUnavailable for unexpected payload`() {
        whenever(gateway.getLatestMatches(clubId))
            .thenReturn(EaApiResult.UnexpectedPayload(RuntimeException("bad json")))

        val result = service.notifyLatest()

        assertThat(result).isEqualTo(NotifyResult.EaUnavailable)
        verify(webhookClient, never()).send(any())
    }

    @Test
    fun `returns NoMatches when EA returns no matches`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.NoMatches)

        val result = service.notifyLatest()

        assertThat(result).isEqualTo(NotifyResult.NoMatches)
        verify(webhookClient, never()).send(any())
    }

    @Test
    fun `picks the most recent match when multiple returned`() {
        val older = match("old", ts = 1000L)
        val newer = match("new", ts = 9000L)
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(older, newer)))

        val result = service.notifyLatest()

        assertThat(result).isInstanceOf(NotifyResult.Sent::class.java)
        verify(store).saveIds(setOf("new"))
    }

    @Test
    fun `concurrent second call returns Busy`() {
        val latch = CountDownLatch(1)
        whenever(gateway.getLatestMatches(clubId)).thenAnswer {
            latch.await(2, TimeUnit.SECONDS)
            EaApiResult.Success(listOf(match("m1")))
        }

        val executor = Executors.newFixedThreadPool(2)
        val firstFuture = executor.submit<NotifyResult> { service.notifyLatest() }
        Thread.sleep(100)
        val secondResult = service.notifyLatest()
        latch.countDown()
        val firstResult = firstFuture.get(3, TimeUnit.SECONDS)
        executor.shutdown()

        assertThat(secondResult).isEqualTo(NotifyResult.Busy)
        assertThat(firstResult).isInstanceOf(NotifyResult.Sent::class.java)
    }

    // -- Immediate EA call (manual refresh) --

    @Test
    fun `notifyLatest calls EA API immediately without waiting for scheduler`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.NoMatches)

        // Must return synchronously; if it waited 2 minutes the test would time out.
        service.notifyLatest()

        verify(gateway).getLatestMatches(clubId)
    }

    @Test
    fun `runIfIdle succeeds after notifyLatest completes - lock is released`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.NoMatches)
        service.notifyLatest()

        var ran = false
        val acquired = service.runIfIdle { ran = true }

        assertThat(acquired).isTrue()
        assertThat(ran).isTrue()
    }

    @Test
    fun `scheduler can run normally after manual refresh completes`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))

        // Manual refresh publishes m1
        service.notifyLatest()

        // Now simulate a scheduler cycle via runIfIdle — it must not be locked out
        var schedulerRan = false
        val acquired = service.runIfIdle { schedulerRan = true }

        assertThat(acquired).isTrue()
        assertThat(schedulerRan).isTrue()
    }

    // -- History webhook --

    @Test
    fun `history webhook is called for newly published match`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))

        service.notifyLatest()

        verify(webhookClient).sendHistory(any())
    }

    @Test
    fun `history webhook is not called for already published match`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        service.notifyLatest()

        verify(webhookClient, never()).sendHistory(any())
    }

    @Test
    fun `history webhook failure does not affect main delivery result`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        // sendHistory is fire-and-forget and never throws — verify main result is Sent regardless
        org.mockito.kotlin.doNothing().whenever(webhookClient).sendHistory(any())

        val result = service.notifyLatest()

        assertThat(result).isInstanceOf(NotifyResult.Sent::class.java)
        verify(webhookClient).send(any())
    }

    @Test
    fun `manual refresh does not send already published match to history`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        service.notifyLatest()

        verify(webhookClient, never()).send(any())
        verify(webhookClient, never()).sendHistory(any())
    }

    // -- resendLatest (force-resend) --

    @Test
    fun `resendLatest sends match even when already published`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        val result = service.resendLatest()

        assertThat(result).isInstanceOf(NotifyResult.ForceSent::class.java)
        verify(webhookClient).send(any())
    }

    @Test
    fun `resendLatest does not modify published IDs store`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        service.resendLatest()

        verify(store, never()).saveIds(any())
    }

    @Test
    fun `resendLatest does not remove match from published IDs`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("m1", "m2", "m3"))

        service.resendLatest()

        // Verify saveIds was never called, so existing IDs remain untouched
        verify(store, never()).saveIds(any())
    }

    @Test
    fun `after resendLatest notifyLatest still skips already published match`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        // Force resend first
        val resendResult = service.resendLatest()
        assertThat(resendResult).isInstanceOf(NotifyResult.ForceSent::class.java)

        // Normal notify should still skip
        val notifyResult = service.notifyLatest()
        assertThat(notifyResult).isInstanceOf(NotifyResult.AlreadyPublished::class.java)
    }

    @Test
    fun `resendLatest sends to history webhook`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        service.resendLatest()

        verify(webhookClient).sendHistory(any())
    }

    @Test
    fun `resendLatest returns NoMatches when no matches available`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.NoMatches)

        val result = service.resendLatest()

        assertThat(result).isEqualTo(NotifyResult.NoMatches)
    }

    @Test
    fun `resendLatest returns EaUnavailable when EA API fails`() {
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Unavailable(500, "error"))

        val result = service.resendLatest()

        assertThat(result).isEqualTo(NotifyResult.EaUnavailable)
    }

    @Test
    fun `resendLatest returns DiscordError when Discord fails`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        doThrow(DiscordDeliveryException("HTTP 500")).whenever(webhookClient).send(any())

        val result = service.resendLatest()

        assertThat(result).isEqualTo(NotifyResult.DiscordError)
    }

    @Test
    fun `resendLatest can resend same match multiple times`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(setOf("m1"))

        val result1 = service.resendLatest()
        val result2 = service.resendLatest()
        val result3 = service.resendLatest()

        assertThat(result1).isInstanceOf(NotifyResult.ForceSent::class.java)
        assertThat(result2).isInstanceOf(NotifyResult.ForceSent::class.java)
        assertThat(result3).isInstanceOf(NotifyResult.ForceSent::class.java)
        verify(webhookClient, org.mockito.kotlin.times(3)).send(any())
    }

    @Test
    fun `resendLatest returns Busy when another operation is in progress`() {
        val latch = CountDownLatch(1)
        whenever(gateway.getLatestMatches(clubId)).thenAnswer {
            latch.await(2, TimeUnit.SECONDS)
            EaApiResult.Success(listOf(match("m1")))
        }

        val executor = Executors.newFixedThreadPool(2)
        val firstFuture = executor.submit<NotifyResult> { service.resendLatest() }
        Thread.sleep(100)
        val secondResult = service.resendLatest()
        latch.countDown()
        val firstResult = firstFuture.get(3, TimeUnit.SECONDS)
        executor.shutdown()

        assertThat(secondResult).isEqualTo(NotifyResult.Busy)
        assertThat(firstResult).isInstanceOf(NotifyResult.ForceSent::class.java)
    }

    @Test
    fun `resendLatest uses current DiscordEmbedBuilder`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))

        service.resendLatest()

        // Verify send was called with any payload (proving DiscordEmbedBuilder.build was used)
        verify(webhookClient).send(any())
    }

    @Test
    fun `resendLatest sends new match even if not in published list`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))
        whenever(store.loadIds()).thenReturn(emptySet())

        val result = service.resendLatest()

        // For a new match, resendLatest still returns ForceSent (not Sent)
        // because it does not persist the ID
        assertThat(result).isInstanceOf(NotifyResult.ForceSent::class.java)
        verify(webhookClient).send(any())
        verify(store, never()).saveIds(any())
    }

    // -- Helpers --

    private fun match(id: String, ts: Long = 5000L) = MatchResponse(
        matchId = id,
        timestamp = ts,
        clubs = mapOf(
            "12345" to ClubMatchEntry(details = ClubDetails(name = "Test FC"), score = "2", result = "1"),
            "99999" to ClubMatchEntry(details = ClubDetails(name = "Opp"),     score = "0", result = "0"),
        ),
        players = emptyMap(),
    )
}

package com.eafc26.discordstats.service

import com.eafc26.discordstats.config.AppProperties
import com.eafc26.discordstats.config.EaProperties
import com.eafc26.discordstats.discord.DiscordDeliveryException
import com.eafc26.discordstats.discord.DiscordWebhookClient
import com.eafc26.discordstats.ea.EaApiResult
import com.eafc26.discordstats.ea.EaClubsGateway
import com.eafc26.discordstats.ea.model.ClubDetails
import com.eafc26.discordstats.ea.model.ClubMatchEntry
import com.eafc26.discordstats.ea.model.MatchResponse
import com.eafc26.discordstats.store.PublishedMatchStore
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test
import org.mockito.kotlin.any
import org.mockito.kotlin.doThrow
import org.mockito.kotlin.mock
import org.mockito.kotlin.never
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import java.util.concurrent.CountDownLatch
import java.util.concurrent.Executors
import java.util.concurrent.TimeUnit

class NotifyLatestServiceTest {

    private lateinit var gateway: EaClubsGateway
    private lateinit var store: PublishedMatchStore
    private lateinit var webhookClient: DiscordWebhookClient
    private lateinit var service: NotifyLatestService

    private val clubId = "12345"
    private val props = AppProperties(ea = EaProperties(clubId = "12345", clubName = "Test FC"))

    @BeforeEach
    fun setUp() {
        gateway = mock()
        store = mock()
        webhookClient = mock()
        service = NotifyLatestService(gateway, store, webhookClient, props)
        whenever(store.loadIds()).thenReturn(emptySet())
    }

    @Test
    fun `sends notification for new match and persists match id`() {
        val match = match("m1")
        whenever(gateway.getLatestMatches(clubId)).thenReturn(EaApiResult.Success(listOf(match)))

        val result = service.notifyLatest()

        assertThat(result).isInstanceOf(NotifyResult.Sent::class.java)
        val sent = result as NotifyResult.Sent
        assertThat(sent.summary).contains("Test FC")
        verify(webhookClient).send(any())
